import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';

const Electrical = () => {
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);

  // Category 'electrical' ke liye data fetch karna
  useEffect(() => {
    const fetchElectricalPosts = async () => {
      try {
        const res = await axios.get('http://localhost:5000/api/blog/electrical');
        setPosts(res.data);
      } catch (err) {
        console.error("Electrical posts fetch error:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchElectricalPosts();
  }, []);

  return (
    <div className="bg-white antialiased w-full">

      {/* 1. HEADER SECTION */}
      <section className="pt-32 pb-20 px-6 md:px-16 w-full bg-gradient-to-r from-[#141a1f] to-[#111c2e] text-white">
        <div className="w-full">
          <h1 className="text-5xl md:text-7xl font-black tracking-tighter mb-6">
            Electrical <span className="text-orange-400">Solutions</span>
          </h1>
          <p className="text-orange-100 text-lg md:text-xl font-light max-w-3xl leading-relaxed">
            Powering progress with specialized manpower for grids, renewable energy, and heavy industrial wiring.
          </p>
        </div>
      </section>

      {/* 2. DYNAMIC SPOTLIGHT SECTION */}
      <section className="w-full bg-white border-t border-gray-100">
        <div className="py-16 px-6 md:px-16 w-full bg-gray-50 flex justify-between items-center">
          <div>
            <h2 className="text-5xl font-black text-gray-900 tracking-tighter">
              Industrial <span className="text-orange-600">Spotlight</span>
            </h2>
            <div className="h-1.5 w-24 bg-orange-500 mt-4 rounded-full"></div>
          </div>
          {!loading && (
            <span className="bg-white px-4 py-2 rounded-full border border-gray-200 text-[10px] font-black text-gray-400 uppercase tracking-widest">
              {posts.length} Updates
            </span>
          )}
        </div>

        <div className="w-full flex flex-col">
          {loading ? (
            <div className="py-32 text-center flex flex-col items-center justify-center space-y-4">
              <div className="w-12 h-12 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
              <p className="font-black text-gray-400 uppercase text-xs tracking-widest">Loading Electrical Insights...</p>
            </div>
          ) : posts.length > 0 ? (
            posts.map((post, index) => (
              <div 
                key={post._id || index} 
                className="w-full px-6 md:px-16 py-16 flex flex-col md:flex-row items-center gap-12 border-b border-gray-100 last:border-b-0 hover:bg-blue-50/20 transition-colors group"
              >
                {/* Image/Icon Box */}
                <div className="flex-shrink-0">
                  <div className="h-44 w-44 bg-white border-2 border-orange-100 rounded-full flex items-center justify-center text-7xl shadow-2xl overflow-hidden relative group">
                    {post.image ? (
                      <img src={post.image} alt={post.title} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" />
                    ) : (
                      <span className="text-orange-500 group-hover:drop-shadow-[0_0_15px_rgba(249,115,22,0.5)] transition-all">⚡</span>
                    )}
                    <div className="absolute inset-0 border-4 border-dashed border-orange-200 rounded-full animate-[spin_20s_linear_infinite] opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none"></div>
                  </div>
                </div>

                {/* Text Content */}
                <div className="flex-grow">
                  <div className="flex items-center gap-3 mb-4">
                    <span className="text-orange-600 font-black text-[10px] uppercase tracking-widest bg-orange-50 px-3 py-1 rounded-full">
                      Electrical News
                    </span>
                    <span className="text-gray-400 font-bold text-[10px] uppercase tracking-widest">
                      {post.date || 'New Entry'}
                    </span>
                  </div>
                  <h3 className="text-3xl md:text-4xl font-black text-gray-950 mb-4 tracking-tighter group-hover:text-orange-600 transition-colors">
                    {post.title}
                  </h3>
                  <p className="text-gray-700 text-xl leading-relaxed italic max-w-5xl">
                    "{post.description}"
                  </p>
                </div>
              </div>
            ))
          ) : (
            <div className="py-32 text-center">
              <p className="text-gray-300 text-2xl font-black uppercase tracking-tighter italic">No spotlight posts found for Electrical.</p>
            </div>
          )}
        </div>
      </section>

      {/* 3. CAREER BANNER */}
      <section className="py-24 px-6 md:px-16 w-full bg-white">
        <div className="w-full bg-gradient-to-br from-gray-900 to-black rounded-[4rem] p-12 md:p-20 flex flex-col md:flex-row items-center justify-between text-white shadow-[0_50px_100px_-20px_rgba(0,0,0,0.2)] relative overflow-hidden">
          <div className="absolute top-0 right-0 w-64 h-64 bg-orange-600/20 rounded-full blur-[100px]"></div>

          <div className="md:w-2/3 relative z-10">
            <h2 className="text-4xl md:text-6xl font-black mb-6 tracking-tighter leading-tight">
              Start Your Career <br /> <span className="text-orange-500">With Hudson Today</span>
            </h2>
            <p className="text-gray-400 text-xl mb-10 max-w-xl font-medium">
              We are actively looking for certified electricians and grid engineers.
            </p>
            <Link to="/careers">
              <button className="bg-orange-600 text-white px-14 py-6 rounded-2xl font-black text-xl hover:bg-white hover:text-orange-600 transition-all shadow-xl active:scale-95">
                Apply Now
              </button>
            </Link>
          </div>

          <div className="hidden md:flex md:w-1/3 justify-end relative z-10">
            <div className="h-72 w-72 border-4 border-white/5 rounded-full flex items-center justify-center animate-pulse">
               <span className="text-9xl opacity-20 filter grayscale">⚡</span>
            </div>
          </div>
        </div>
      </section>

    </div>
  );
};

export default Electrical;
